&quot;, ptr3, ptr3 - 2);return 0;&#125; 指向const的指针不能用于改变值。考虑下面的代码： 12double rates[5] = &#123;88.99, 100.12, 59.45, 183.11, 340.5&#125;;const double * pd = rates; // pd指向数组的首元素 第2行代码把pd指向的double类型的值声明为const，这表明不能使用pd 来更改它所指向的值： 123\*pd = 29.89; // 不允许pd[2] = 222.22; //不允许rates[0] = 99.99; // 允许，因为rates未被const限定 无论是使用指针表示法还是数组表示法，都不允许使用pd修改它所指向数据的值但是要注意，因为rates并未被声明为const，所以仍然可以通过 rates修改元素的值。另外，可以让pd指向别处：pd++; /* 让pd指向rates[1] – 没问题 */ 指向 const 的指针通常用于函数形参中，表明该函数不会使用指针改变数据 1void show_array(const double *ar, int n); 把const数据或非const 数据的地址初始化为指向const的指针或为其赋值是合法的 double rates[5] = {88.99, 100.12, 59.45, 183.11, 340.5};const double locked[4] = {0.08, 0.075, 0.0725, 0.07};const double * pc = rates; // 有效pc = locked; //有效 枚举 以用枚举类型（enumerated type）声明符号名称来表示整型常量 使用enum关键字，可以创建一个新“类型”并指定它可具有的值（实际上，enum 常量是int类型，因此，只要能使用int类型的地方就可以使用枚举类型） 12enum spectrum &#123;red, orange, yellow, green, blue, violet&#125;;enum spectrum color; 第1个声明中花括号内的标 识符枚举了spectrum变量可能有的值。因此,color 可能的值是 red、 orange、yellow等 这些符号常量被称为枚举符（enumerator）。 字符串函数####fgets()函数 函数的第2个参数指明了读入字符的最大数量。 如果该参数的值是n，那么fgets()将读入n-1个字符， 或者读到遇到的第一个换行符为止。 fgets()读到一个换行符，会把它储存在字符串中 函数的第3 个参数指明要读入的文件。 如果读入从键盘输入的数 据，则以stdin（标准输入）作为参数 ####fputs函数 fputs()函数的第2个参数指明它要写入的文件。 如果要显示在计算机显示器上，应使用stdout（标准输出）作为该参数 puts()函数返回指向 char的指针 如果一切进行顺利,该函数返回的地址与传入的第1个参数相同 但是,如果函数读到文件结尾，它将返回一个特殊的指针：空指针（null pointer） 该指针保证不会指向有效的数据，所以可用于标识这种特殊情况 123456789101112131415161718#include &lt;stdio.h&gt;#define STLEN 14int main(void)&#123;char words[STLEN];puts(&quot;Enter a string, please.&quot;);fgets(words, STLEN, stdin);printf(&quot;Your string twice (puts(), then fputs()):
&quot;);puts(words);fputs(words, stdout);puts(&quot;Enter another string, please.&quot;);fgets(words, STLEN, stdin);printf(&quot;Your string twice (puts(), then fputs()):
&quot;);puts(words);fputs(words, stdout);puts(&quot;Done.&quot;);return 0;&#125; 12345678910111213141516171819202122#include &lt;stdio.h&gt;#define STLEN 10int main(void)&#123;char words[STLEN];int i;puts(&quot;Enter strings (empty line to quit):&quot;);while (fgets(words, STLEN, stdin) != NULL &amp;&amp; words[0] != &apos;
