&quot;);return 0;&#125; malloc()函数 该函数接受一个参数：所需的内存字节数。 malloc()函数会找 到合适的空闲内存块，这样的内存是匿名的。也就是说， malloc()分配内存，但是不会为其赋名 然而，它确实返回动态分配内存块的首字节地址。 因此，可以把该地址赋给一个指针变量，并使用指针访问这块内存 malloc()的返回类型通常被定义为指向char的指针。 然而， 从ANSI C标准开始，C使用一个新的类型：指向void的指针 该类型相当于 一个“通用指针” 123double * ptd;ptd = (double *) malloc(30 * sizeof(double));以上代码为30个double类型的值请求内存空间，并设置ptd指向该位置。 通常，malloc()要与free()配套使用。free()函数的参数是之前malloc()返 回的地址，该函数释放之前malloc()分配的内存。 12345678910111213141516171819202122232425262728293031323334353637#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt; /* 为 malloc()、free()提供原型 */int main(void)&#123;double * ptd;int max;int number;int i = 0;puts(&quot;What is the maximum number of type double entries?&quot;);if (scanf(&quot;%d&quot;, &amp;max) != 1)&#123;puts(&quot;Number not correctly entered -- bye.&quot;);exit(EXIT_FAILURE);&#125;ptd = (double *) malloc(max * sizeof(double));if (ptd == NULL)&#123;puts(&quot;Memory allocation failed. Goodbye.&quot;);exit(EXIT_FAILURE);&#125;/* ptd 现在指向有max个元素的数组 */puts(&quot;Enter the values (q to quit):&quot;);while (i &lt; max &amp;&amp; scanf(&quot;%lf&quot;, &amp;ptd[i]) == 1)++i;printf(&quot;Here are your %d entries:
